const item = $input.first().json;
const prompt = `Crie um briefing criativo estruturado em markdown com: resumo executivo, objetivo, publico, tom de comunicacao, narrativa, ideias de campanha, prompts visuais, checklist de producao e proximos passos.

Cliente: ${item.client}
Tipo: ${item.project_type}
Objetivo: ${item.objective}
Publico: ${item.audience}
Canais: ${item.channels}
Referencias: ${item.references}`;
return [{ json: { ...item, prompt } }];

const response = $input.first().json;
const brief = response.choices?.[0]?.message?.content || JSON.stringify(response);
return [{ json: { creative_brief_markdown: brief, created_at: new Date().toISOString() } }];
